# Let me write a robust solver step by step

def solve(grid):
    import numpy as np
    grid = np.array(grid)
    H, W = grid.shape

    # Step 1: Find the 5-bordered box
    fives = np.argwhere(grid == 5)
    box_r_min, box_c_min = fives.min(axis=0)
    box_r_max, box_c_max = fives.max(axis=0)

    # Extract the box (this will be the output base)
    box = grid[box_r_min:box_r_max+1, box_c_min:box_c_max+1].copy()

    # Step 2: Find background color (most common in grid, excluding 5)
    flat = grid.flatten()
    counts = np.bincount(flat)
    counts[5] = 0  # exclude 5
    bg = int(np.argmax(counts))

    # Step 3: Find the inner area of the box
    inner = box[1:-1, 1:-1]

    # Step 4: Find block positions and colors in the box
    # Blocks are solid rectangles of non-bg color
    inner_colors = set(int(x) for x in np.unique(inner)) - {bg}

    # Find block size: look at first non-bg block
    blocks = []
    visited = np.zeros_like(inner, dtype=bool)
    for r in range(inner.shape[0]):
        for c in range(inner.shape[1]):
            if inner[r, c] != bg and not visited[r, c]:
                color = int(inner[r, c])
                # Find extent of this solid block
                r2, c2 = r, c
                while r2 + 1 < inner.shape[0] and inner[r2+1, c] == color:
                    r2 += 1
                while c2 + 1 < inner.shape[1] and inner[r, c2+1] == color:
                    c2 += 1
                # Mark visited
                for rr in range(r, r2+1):
                    for cc in range(c, c2+1):
                        visited[rr, cc] = True
                blocks.append((r, c, r2-r+1, c2-c+1, color))

    block_h = blocks[0][2]
    block_w = blocks[0][3]

    # Step 5: Find key pairs outside the box
    # Key pairs have pattern: A A B B / A A A B / A A B B (3 rows, 4 cols)
    color_map = {}  # primary -> secondary

    for r in range(H - 2):
        for c in range(W - 3):
            # Skip if inside the box
            if box_r_min <= r <= box_r_max and box_c_min <= c <= box_c_max:
                continue
            if box_r_min <= r+2 <= box_r_max and box_c_min <= c <= box_c_max:
                continue

            a = int(grid[r, c])
            if a == bg or a == 5:
                continue

            # Check pattern
            expected = [
                [a, a, None, None],
                [a, a, a, None],
                [a, a, None, None]
            ]
            match = True
            b = None
            for dr in range(3):
                for dc in range(4):
                    val = int(grid[r+dr, c+dc])
                    if expected[dr][dc] == a:
                        if val != a:
                            match = False
                            break
                    elif expected[dr][dc] is None:
                        if val == a or val == bg or val == 5:
                            match = False
                            break
                        if b is None:
                            b = val
                        elif val != b:
                            match = False
                            break
                if not match:
                    break

            if match and b is not None:
                color_map[a] = b

    # Step 6: Find templates for each color present in the box
    # Templates are patterns of a single color (+ bg) outside the box
    # with size block_h x block_w
    templates = {}

    # For each inner color, find its template
    for color in inner_colors:
        # Find all occurrences of this color outside the box
        mask = np.zeros_like(grid, dtype=bool)
        for r in range(H):
            for c in range(W):
                if grid[r, c] == color:
                    # Check if outside the box
                    if r < box_r_min or r > box_r_max or c < box_c_min or c > box_c_max:
                        mask[r, c] = True

        if not np.any(mask):
            continue

        # Find connected components of this color outside box
        from scipy import ndimage
        labeled, num = ndimage.label(mask)

        for comp in range(1, num + 1):
            comp_cells = np.argwhere(labeled == comp)
            cr_min, cc_min = comp_cells.min(axis=0)
            cr_max, cc_max = comp_cells.max(axis=0)
            comp_h = cr_max - cr_min + 1
            comp_w = cc_max - cc_min + 1

            # Check if this is a template (right size, not a key pair component)
            if comp_h == block_h and comp_w == block_w:
                # Extract template
                tmpl = np.full((block_h, block_w), bg)
                for cell in comp_cells:
                    tmpl[cell[0] - cr_min, cell[1] - cc_min] = color
                templates[color] = tmpl
                break

    # Step 7: Apply transformation
    output = box.copy()
    for r, c, bh, bw, color in blocks:
        if color in templates and color in color_map:
            tmpl = templates[color]
            mapped_color = color_map[color]
            for dr in range(bh):
                for dc in range(bw):
                    if tmpl[dr, dc] == color:
                        output[1+r+dr, 1+c+dc] = mapped_color
                    else:
                        output[1+r+dr, 1+c+dc] = bg

    return output.tolist()

# Test on training examples
for i, s in enumerate(train_samples):
    result = solve(s['input'])
    expected = s['output']
    match = result == expected
    print(f"Example {i}: {'PASS' if match else 'FAIL'}")
    if not match:
        r = np.array(result)
        e = np.array(expected)
        diff = np.sum(r != e)
        print(f"  Differences: {int(diff)} cells")

