                r2, c2 = r, c
                while r2 + 1 < inner.shape[0] and inner[r2+1, c] == color:
                    r2 += 1
                while c2 + 1 < inner.shape[1] and inner[r, c2+1] == color:
                    c2 += 1
                # Mark visited
                for rr in range(r, r2+1):
                    for cc in range(c, c2+1):
                        visited[rr, cc] = True
                blocks.append((r, c, r2-r+1, c2-c+1, color))

